class Solution:
    def minSubsequence(self, nums):
        nums_sorted = sorted(nums, reverse=True)
        total = sum(nums)
        acc = 0
        result = []
        for v in nums_sorted:
            acc += v
            result.append(v)
            if acc > total - acc:
                return result
        return result

