var minSubsequence = function(nums) {
    nums.sort((a, b) => b - a);
    const total = nums.reduce((s, x) => s + x, 0);
    let acc = 0;
    const result = [];
    for (const v of nums) {
        acc += v;
        result.push(v);
        if (acc > total - acc) return result;
    }
    return result;
};
